def solution(limit: int = 12000) -> int:
    """
    Uses a recursive Farey sequence approach (Stern-Brocot) to count fractions between 1/3 and 1/2.
    """
    def count_between(n1, d1, n2, d2):
        # Mediant is (n1+n2) / (d1+d2)
        nm, dm = n1 + n2, d1 + d2
        if dm > limit:
            return 0
        return 1 + count_between(n1, d1, nm, dm) + count_between(nm, dm, n2, d2)

    # Count between 1/3 and 1/2
    return count_between(1, 3, 1, 2)


